VALUES
  ('disabled-c5fb3965-moex-00131', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '關於應為初設戶籍登記之情形，下列敘述何者錯誤？', '["原有戶籍國民，經許可回復中華民國國籍者", "大陸地區人民或香港、澳門居民，經核准定居", "外國人歸化後，經核准定居", "無國籍人回復國籍後，經核准定居"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00132', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '關於遷出登記之相關規定，下列敘述何者正確？', '["遷出原鄉3個月以上，不論原因為何，均應為遷出登記", "全戶遷徙時，對於出境雖未滿2年者，亦應隨同辦理遷徙登記", "我國國民出境後，如不欲遭遷出登記，只要在 2 年內持合法證照入境 即可", "出境 2 年以上，應為遷出登記，但因不可抗力因素（如 COVID-19）致 難以返國者，不在此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00133', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '基於下列何項理由遷出原鄉（鎮、市、區）超過法定期間後，必須依戶籍 法辦理遷出登記？', '["因犯罪進入矯正機關服刑", "到其他縣市就讀大學", "隨我國籍遠洋漁船出海作業", "因公被調任至其他縣市任職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00134', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '戶籍登記事項錯誤，係因戶政事務所作業錯誤所致者，該管戶政事務所應 如何辦理？', '["查明更正，並通知當事人或原申請人", "廢止原戶籍登記，並另為正確之戶籍登記", "撤銷原戶籍登記，並另為正確之戶籍登記", "其為行政程序法第101條所稱之顯然誤寫，得依職權隨時更正，毋須通 知當事人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00135', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '下列何者依戶籍法不得為出生地登記之申請人？', '["新生兒之父母", "新生兒之祖父母", "新生兒所在家庭之戶長", "新生兒居住地之地方檢察署檢察官"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00136', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '某甲從社區大樓5樓搬家到同一棟社區大樓12樓，應辦理下列何種登記？', '["住址變更登記", "遷入登記", "遷出登記", "分合戶登記"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00137', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '依民國 111 年 5 月 10 日修正之死亡資料通報辦法規定，戶政事務所於接 獲司法院通報之宣告死亡事件裁判書後之處理程序，下列何者正確？', '["戶政事務所接獲死亡資料，應於7日內依規定處理", "通知應為申請之人限期辦理死亡宣告登記，未依限辦理者，戶政事務所 於查核當事人戶籍資料後，得逕為登記", "發現通報之死亡資料有錯漏者，應函請內政部查明處理", "免經催告程序，逕為死亡宣告登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00138', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '依戶籍法規定，下列何項戶籍事務的辦理，無從在全國任一戶政事務所為 之？', '["申請戶籍謄本", "全面換領戶口名簿", "申請結婚證明書", "申請親等關聯資料"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00139', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '甲認領其非婚生子女乙，關於認領登記，下列敘述何者正確？', '["認領登記，以甲或乙為申請人", "甲得以書面委託他人申請，無須戶政事務所核准", "如經戶政事務所催告仍無人申請時，戶政事務所應逕行登記", "戶政事務所查驗認領登記之證明文件後，得以影本留存，無須留存文件 之正本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00140', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '下列何者非屬得依戶籍法辦理戶口清查之機關？', '["新北市板橋區戶政事務所", "內政部", "臺灣臺北地方檢察署", "桃園市政府"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
